import Link from "next/link";

// shadcn
import { Button } from "@/components/ui/button";
import { Separator } from "@/components/ui/separator";

// project
import branding from "@/branding.json";

// constants
const footerLinks = [
  { label: "About Us", href: "#" },
  { label: "Services", href: "#" },
  { label: "Privacy", href: "#" },
  { label: "Stories", href: "#" },
  { label: "Contact", href: "#" }
];

//  ------------------------------ | FOOTER - 9 | ------------------------------  //

export default function Footer9() {
  return (
    <footer className="py-12 md:py-20">
      <div className="container mx-auto px-4">
        <div className="grid grid-cols-12 gap-y-6 items-center">
          {/* Navigation Links Section */}
          <div className="col-span-12 md:col-span-8 mb-6">
            <nav className="flex flex-wrap items-center gap-x-6 gap-y-6 justify-start">
              {footerLinks.map((link) => (
                <Link
                  key={link.label}
                  href={link.href}
                  className="text-slate-500 hover:text-primary transition-colors text-md font-medium"
                >
                  {link.label}
                </Link>
              ))}
            </nav>
          </div>

          {/* Right-aligned Call to Action */}
          <div className="col-span-12 md:col-span-4 flex justify-start items-center">
            <Button size="lg">Download for free</Button>
          </div>

          {/* Separator Section */}
          <div className="col-span-12">
            <Separator className="bg-slate-300" />
          </div>

          {/* Copyright/Description Section */}
          <div className="col-span-12">
            <p className="text-slate-400 text-md max-w-4xl">
              &copy; {branding.brandName} UI Kit. At half-past eight the door opened, the
              policeman appeared and requesting them.
            </p>
          </div>
        </div>
      </div>
    </footer>
  );
}
